/**
 * 鍒涘缓鏂颁换鍔n * 鏀寔涓ょ妯″紡锛歕n * 1) multipart/form-data: 鏈嶅姟绔帴鏀舵枃浠跺苟涓婁紶鍒?Storage锛堟湰鍦?灏忔枃浠跺吋瀹癸級
 * 2) application/json: 瀹㈡埛绔凡鐩翠紶 Storage锛屾湇鍔＄浠呭啓鍏ヤ换鍔″厓鏁版嵁锛堢敓浜ф帹鑽愶級
 */
export async function POST(req: Request) {
  console.log(`${LOG} POST 鍒涘缓浠诲姟`);

  const supabase = await createSupabaseServerClient();
  const admin = createSupabaseAdminClient();

  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    console.log(`${LOG} 鉁?鏈璇乣);
    return jsonError("unauthorized", "Not authenticated", { status: 401 });
  }

  console.log(`${LOG} 鐢ㄦ埛: ${user.id.slice(0, 8)}... / ${user.email}`);

  const bucket = process.env.SUPABASE_STORAGE_BUCKET_AUDIO || "audio";
  const contentType = req.headers.get("content-type") || "";

  let title: string | null = null;
  let projectId: string | null = null;
  let guestName: string | null = null;
  let interviewerName: string | null = null;
  let sourceType = "audio_upload";
  let captureMode = "upload";
  let fileName = "";
  let fileSize = 0;
  let mimeType = "";
  let storagePath = "";
  let uploadedByClient = false;
  let uploadedFile: File | null = null;

  let existingJobId: string | null = null;

  if (contentType.includes("application/json")) {
    uploadedByClient = true;

    const body = (await req.json()) as JsonUploadPayload & { existingJobId?: string };
    title = typeof body.title === "string" ? body.title : null;
    projectId = typeof body.projectId === "string" ? body.projectId : null;
    existingJobId = typeof body.existingJobId === "string" ? body.existingJobId : null;
    guestName = typeof body.guestName === "string" ? body.guestName : null;
    interviewerName = typeof body.interviewerName === "string" ? body.interviewerName : null;
    sourceType = typeof body.sourceType === "string" ? body.sourceType : sourceType;
    captureMode = typeof body.captureMode === "string" ? body.captureMode : captureMode;
    fileName = typeof body.fileName === "string" ? body.fileName : "";
    storagePath = typeof body.storagePath === "string" ? body.storagePath : "";
    mimeType = typeof body.mimeType === "string" ? body.mimeType : "";
    fileSize = Number(body.fileSize || 0);

    if (isLiveCapturePayload(body)) {
      uploadedByClient = false;
      fileName = "";
      storagePath = "";
      mimeType = "";
      fileSize = 0;
      sourceType = "live_capture";
      captureMode = "live";
    } else if (!fileName || !storagePath || !Number.isFinite(fileSize) || fileSize <= 0) {
      console.log(`${LOG} 鉁?JSON payload 闈炴硶`);
      return jsonError("invalid_payload", "Invalid upload metadata", { status: 400 });
    }

    if (storagePath && !storagePath.startsWith(`${user.id}/`)) {
      console.log(`${LOG} 鉁?storagePath 涓嶅睘浜庡綋鍓嶇敤鎴? ${storagePath}`);
      return jsonError("invalid_payload", "Invalid storage path", { status: 400 });
    }

    // 瀹㈡埛绔洿浼犳ā寮忥細鍏堥獙璇佹枃浠剁‘瀹炲凡瀛樺湪锛岄伩鍏嶅啓鍏ュ潖鏁版嵁
    if (storagePath) {
      const { error: verifyError } = await admin.storage
        .from(bucket)
        .createSignedUrl(storagePath, 60);

      if (verifyError) {
        console.log(`${LOG} 鉁?鐩翠紶鏂囦欢涓嶅瓨鍦? ${verifyError.message}`);
        return jsonError("upload_missing", "Uploaded file not found in storage", { status: 400 });
      }
    }
  } else {
    const formData = await req.formData();
    const fileEntry = formData.get("file");
    title = formData.get("title")?.toString() || null;
    projectId = formData.get("projectId")?.toString() || null;
    existingJobId = formData.get("existingJobId")?.toString() || null;
    guestName = formData.get("guestName")?.toString() || null;
    interviewerName = formData.get("interviewerName")?.toString() || null;
    sourceType = formData.get("sourceType")?.toString() || sourceType;
    captureMode = formData.get("captureMode")?.toString() || captureMode;

    if (!(fileEntry instanceof File)) {
      console.log(`${LOG} 鉁?缂哄皯闊抽鏂囦欢`);
      return jsonError("invalid_file", "Missing audio file", { status: 400 });
    }

    uploadedFile = fileEntry;
    fileName = fileEntry.name;
    fileSize = fileEntry.size;
    mimeType = fileEntry.type || "";
  }

  if (!projectId && !existingJobId) {
    return jsonError("missing_project", "Please create and select a project first", { status: 400 });
  }

  if (projectId) {
    const { data: project } = await supabase
      .from("projects")
      .select("id")
      .eq("id", projectId)
      .eq("user_id", user.id)
      .maybeSingle();

    if (!project) {
      return jsonError("invalid_project", "Selected project does not exist", { status: 400 });
    }
  }

  const fileSizeMb = fileSize / (1024 * 1024);
  if (captureMode === "live") {
    console.log(`${LOG} 瀹炴椂璁胯皥妯″紡锛氬垱寤虹┖ Job锛岄煶棰戝悗缁疄鏃惰繘鍏?ASR`);
  } else {
    const plan = await getUserPlan(supabase, user.id);
    console.log(`${LOG} 濂楅: ${plan.plan} / 鍗曟枃浠朵笂闄? ${plan.maxFileSizeMb}MB`);
    console.log(`${LOG} 鏂囦欢: ${fileName} / ${fileSizeMb.toFixed(2)}MB / ${mimeType || "unknown"}`);
    if (fileSizeMb > plan.maxFileSizeMb) {
      console.log(`${LOG} 鉁?鏂囦欢瓒呴檺: ${fileSizeMb.toFixed(2)}MB > ${plan.maxFileSizeMb}MB`);
      return jsonError(
        "file_too_large",
        `File exceeds ${plan.maxFileSizeMb}MB limit`,
        { status: 400 }
      );
    }
  }

  // 鍒涘缓/鏇存柊 Job 璁板綍
  console.log(`${LOG} 鍐欏叆 Job 璁板綍...`);

  let jobDataResult: any = null;
  let jobErrorResult: any = null;

  if (existingJobId) {
    const { data, error } = await supabase
      .from("jobs")
      .update({
        title: title || undefined,
        guest_name: guestName || undefined,
        interviewer_name: interviewerName || undefined,
        status: JOB_STATUS.pending,
        source_type: sourceType,
        capture_mode: captureMode,
        started_at: new Date().toISOString(),
      })
      .eq("id", existingJobId)
      .eq("user_id", user.id)
      .select("*")
      .single();
    jobDataResult = data;
    jobErrorResult = error;
  } else {
    const { data, error } = await supabase
      .from("jobs")
      .insert({
        user_id: user.id,
        project_id: projectId,
        title,
        guest_name: guestName,
        interviewer_name: interviewerName,
        status: JOB_STATUS.pending,
        source_type: sourceType,
        capture_mode: captureMode,
        started_at: new Date().toISOString(),
      })
      .select("*")
      .single();
    jobDataResult = data;
    jobErrorResult = error;
  }

  const job = jobDataResult as JobRow | null;

  if (jobErrorResult || !job) {
    console.error(`${LOG} 鉁?Job 鍐欏叆澶辫触:`, jobErrorResult?.message);
    return jsonError("db_error", jobErrorResult?.message || "Failed to upsert job", { status: 500 });
  }

  console.log(`${LOG} 鉁?Job 宸插垱寤? ${job.id}`);

  if (captureMode === "live") {
    return jsonOk({
      jobId: job.id,
      job,
      audioAssetId: null,
    }, { status: 201 });
  }

  if (!uploadedByClient && uploadedFile) {
    // multipart 妯″紡锛氭湇鍔＄璐熻矗涓婁紶锛堟湰鍦板紑鍙戝吋瀹癸級
    const safeFileName = sanitizeFileName(fileName);
    storagePath = `${user.id}/${job.id}/${safeFileName}`;
    console.log(`${LOG} 鍘熷鏂囦欢鍚? ${fileName} 鈫?瀹夊叏鏂囦欢鍚? ${safeFileName}`);
    console.log(`${LOG} 涓婁紶闊抽: ${bucket}/${storagePath} (${fileSizeMb.toFixed(2)}MB)`);

    const fileBuffer = Buffer.from(await uploadedFile.arrayBuffer());
    const { error: uploadError } = await admin.storage
      .from(bucket)
      .upload(storagePath, fileBuffer, {
        contentType: mimeType || "audio/mpeg",
        upsert: false,
      });

    if (uploadError) {
      console.error(`${LOG} 鉁?Storage 涓婁紶澶辫触:`, uploadError.message);
      await admin
        .from("jobs")
        .update({ status: JOB_STATUS.failed, error_message: uploadError.message })
        .eq("id", job.id);
      return jsonError("upload_failed", uploadError.message, { status: 500 });
    }

    console.log(`${LOG} 鉁?闊抽涓婁紶鎴愬姛`);
  } else {
    console.log(`${LOG} 鉁?浣跨敤瀹㈡埛绔洿浼犻煶棰? ${bucket}/${storagePath}`);
  }

  // 鍒涘缓 audio_assets 璁板綍
  const { data: audioAssetData, error: audioError } = await admin
    .from("audio_assets")
    .insert({
      user_id: user.id,
      job_id: job.id,
      storage_path: storagePath,
      file_name: fileName,
      file_size: fileSize,
      mime_type: mimeType || null,
    })
    .select("*")
    .single();

  const audioAsset = audioAssetData as AudioAssetRow | null;

  if (audioError || !audioAsset) {
    console.error(`${LOG} 鉁?audio_assets 鍐欏叆澶辫触:`, audioError?.message);
    await admin
      .from("jobs")
      .update({ status: JOB_STATUS.failed, error_message: audioError?.message })
      .eq("id", job.id);
    return jsonError("db_error", audioError?.message || "Audio asset failed", { status: 500 });
  }

  await admin
    .from("jobs")
    .update({ audio_asset_id: audioAsset.id })
    .eq("id", job.id);

  // 璁板叆鐢ㄩ噺璐︽湰
  await admin.from("credits_ledger").insert({
    user_id: user.id,
    job_id: job.id,
    action: "debit",
    amount: 1,
    unit: "files",
  });

  console.log(`${LOG} 鉁?浠诲姟鍒涘缓瀹屾垚: jobId=${job.id}`);

  return jsonOk({
    jobId: job.id,
    job: {
      ...job,
      audio_asset_id: audioAsset.id,
    } as JobRow,
  });
}

