    setSourceState((prev) => [source, ...prev.filter((item) => item.id !== source.id)]);
    setSelectedProjectId(source.project_id);
    setSelectedSourceId(source.id);
    setSelectedJobId(source.job_id || null);
    setCenterSection("sources");
